| MCP:oTqYHV | const Mock = require('mockjs')
| MCP:oTqYHV | const { param2Obj } = require('./utils')
| MCP:oTqYHV | 
| MCP:oTqYHV | const user = require('./user')
| MCP:oTqYHV | const table = require('./table')
| MCP:oTqYHV | 
| MCP:oTqYHV | const mocks = [...user, ...table]
| MCP:oTqYHV | 
| MCP:oTqYHV | // for front mock
| MCP:oTqYHV | // please use it cautiously, it will redefine XMLHttpRequest,
| MCP:oTqYHV | // which will cause many of your third-party libraries to be invalidated(like progress event).
| MCP:oTqYHV | function mockXHR() {
| MCP:oTqYHV |   // mock patch
| MCP:oTqYHV |   // https://github.com/nuysoft/Mock/issues/300
| MCP:oTqYHV |   Mock.XHR.prototype.proxy_send = Mock.XHR.prototype.send
| MCP:oTqYHV |   Mock.XHR.prototype.send = function () {
| MCP:oTqYHV |     if (this.custom.xhr) {
| MCP:oTqYHV |       this.custom.xhr.withCredentials = this.withCredentials || false
| MCP:oTqYHV | 
| MCP:oTqYHV |       if (this.responseType) {
| MCP:oTqYHV |         this.custom.xhr.responseType = this.responseType
| MCP:oTqYHV |       }
| MCP:oTqYHV |     }
| MCP:oTqYHV |     this.proxy_send(...arguments)
| MCP:oTqYHV |   }
| MCP:oTqYHV | 
| MCP:oTqYHV |   function XHR2ExpressReqWrap(respond) {
| MCP:oTqYHV |     return function (options) {
| MCP:oTqYHV |       let result = null
| MCP:oTqYHV |       if (respond instanceof Function) {
| MCP:oTqYHV |         const { body, type, url } = options
| MCP:oTqYHV |         // https://expressjs.com/en/4x/api.html#req
| MCP:oTqYHV |         result = respond({
| MCP:oTqYHV |           method: type,
| MCP:oTqYHV |           body: JSON.parse(body),
| MCP:oTqYHV |           query: param2Obj(url),
| MCP:oTqYHV |         })
| MCP:oTqYHV |       } else {
| MCP:oTqYHV |         result = respond
| MCP:oTqYHV |       }
| MCP:oTqYHV |       return Mock.mock(result)
| MCP:oTqYHV |     }
| MCP:oTqYHV |   }
| MCP:oTqYHV | 
| MCP:oTqYHV |   for (const i of mocks) {
| MCP:oTqYHV |     Mock.mock(
| MCP:oTqYHV |       new RegExp(i.url),
| MCP:oTqYHV |       i.type || 'get',
| MCP:oTqYHV |       XHR2ExpressReqWrap(i.response)
| MCP:oTqYHV |     )
| MCP:oTqYHV |   }
| MCP:oTqYHV | }
| MCP:oTqYHV | 
| MCP:oTqYHV | module.exports = {
| MCP:oTqYHV |   mocks,
| MCP:oTqYHV |   mockXHR,
| MCP:oTqYHV | }
